        public ShowEmployees build() {
            if (paymentMethod == null) {
                paymentMethod = _SINGLETON_VALUE_PaymentMethod.value();
            }

            return new ShowEmployees(
                uuid, firstName, middleInitial,
                lastName, email, companyUuid,
                managerUuid, version, department,
                terminated, twoPercentShareholder, workEmail,
                onboarded, onboardingStatus, onboardingDocumentsConfig,
                jobs, eligiblePaidTimeOff, terminations,
                garnishments, customFields, dateOfBirth,
                hasSsn, ssn, phone,
                preferredFirstName, paymentMethod, currentEmploymentStatus,
                historical, employeeCode, departmentUuid,
                title, hiredAt, hiddenSsn,
                flsaStatus, applicableTaxIds, memberPortalInvitationStatus,
                partnerPortalInvitationSent, currentHomeAddress, allHomeAddresses)
                .withAdditionalProperties(additionalProperties);
        }


        private static final LazySingletonValue<Optional<? extends PaymentMethod>> _SINGLETON_VALUE_PaymentMethod =
                new LazySingletonValue<>(
                        "payment_method",
                        "\"Check\"",
                        new TypeReference<Optional<? extends PaymentMethod>>() {});
